function cleanText(text) {
  return String(text || '')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n[ \t]+/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function stripMarkdownArtifacts(text) {
  return String(text || '')
    // images like ![](...)
    .replace(/!\[[^\]]*\]\([^)]+\)/g, '')
    // markdown links [text](url) -> text
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1')
    // angle-bracket links <https://...> -> https://...
    .replace(/<([^>]+)>/g, '$1')
    .trim();
}

function extractAnnouncementBody(raw, fallbackTitle = '') {
  let text = cleanText(stripMarkdownArtifacts(raw));

  // Find the real title area
  const titlePatterns = [
    new RegExp(`##\\s+${fallbackTitle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}`, 'i'),
    /^##\s+.+$/m
  ];

  let startIdx = -1;
  for (const pattern of titlePatterns) {
    const match = text.match(pattern);
    if (match) {
      startIdx = match.index;
      break;
    }
  }

  if (startIdx >= 0) {
    text = text.slice(startIdx);
  }

  // Remove generic headings at top
  text = text
    .replace(/^#\s+Announcement\s*/i, '')
    .replace(/^##\s+Breadcrumb\s*/i, '')
    .trim();

  // Cut footer / boilerplate
  const endMarkers = [
    /\n\s*\[?\!?FFIEC logo/i,
    /\n\s*An Official website of the/i,
    /\n\s*\[?\!?Home\]?/i,
    /\n\s*Official websites use \.gov/i,
    /\n\s*Secure \.gov websites use HTTPS/i
  ];

  let endIdx = text.length;
  for (const marker of endMarkers) {
    const match = text.match(marker);
    if (match && match.index < endIdx) {
      endIdx = match.index;
    }
  }
  text = text.slice(0, endIdx).trim();

  // Remove leftover UI boilerplate lines
  const badLinePatterns = [
    /^An official website of the United States government$/i,
    /^Here'?s how you know$/i,
    /^\*\*Official websites use \.gov\*\*$/i,
    /^A \*\*\.gov\*\* website belongs to an official government organization in the United States\.$/i,
    /^\*\*Secure \.gov websites use HTTPS\*\*$/i,
    /^A \*\*lock\*\*.*$/i,
    /^Lock$/i,
    /^Locked padlock$/i,
    /^Home$/i,
    /^close$/i,
    /^Search$/i,
    /^Announcement$/i,
    /^Breadcrumb$/i
  ];

  const lines = text
    .split('\n')
    .map(line => line.trim())
    .filter(Boolean)
    .filter(line => !badLinePatterns.some(re => re.test(line)));

  // Remove duplicate first title marker "## Title"
  let article = lines.join('\n\n')
    .replace(/^##\s+/m, '')
    .trim();

  // Normalize title suffix
  article = article.replace(/\s+\|\s+FFIEC$/i, '').trim();

  return cleanText(article);
}

return items.map(item => {
  const result = item.json.results?.[0] || {};
  const raw = result.raw_content || '';
  const title = (result.title || '').replace(/\s+\|\s+FFIEC$/i, '').trim();
  const url = result.url || '';

  const article_clean = extractAnnouncementBody(raw, title);

  return {
    json: {
      title,
      url,
      article_clean
    }
  };
});

